#include "pytorch_npu_helper.hpp"

at::Tensor average_pooling_3d_impl_npu(const at::Tensor& self, int64_t kernel_size, int64_t stride, int64_t padding) {
    if (stride <= 0) {
        stride = kernel_size;
    }
    bool count_include_pad = false;
    at::Tensor result = at::empty({self.size(0),
                                   self.size(1),
                                   (self.size(2) + 2 * padding - kernel_size) / stride + 1,
                                   (self.size(3) + 2 * padding - kernel_size) / stride + 1,
                                   (self.size(4) + 2 * padding - kernel_size) / stride + 1},
                                   self.options());
    EXEC_NPU_CMD(aclnnAveragePooling3dCustom, self, (int)kernel_size, (int)stride, (int)padding, count_include_pad, result);
    return result;
}

